<?php
if (!defined('ABSPATH')) exit;
class VH360_Giving_Webhook { public static function maybe_handle_checkout_completed($session,$event_id){ if(empty($session['metadata']['type'])||'giving'!==$session['metadata']['type']) return false; $tx_id=absint($session['metadata']['transaction_id']??0); $tx=VH360_Giving_Transactions::get($tx_id); if(!$tx) return new WP_Error('giving_tx_missing','Giving transaction not found.'); if($tx->stripe_event_id===$event_id||$tx->status==='paid') return true; VH360_Giving_Transactions::update($tx_id,array('status'=>'paid','gateway_transaction_id'=>sanitize_text_field($session['payment_intent']??''),'gateway_customer_id'=>sanitize_text_field($session['customer']??''),'gateway_event_id'=>$event_id,'stripe_payment_intent_id'=>sanitize_text_field($session['payment_intent']??''),'stripe_customer_id'=>sanitize_text_field($session['customer']??''),'stripe_event_id'=>$event_id,'given_at'=>current_time('mysql'))); return true; } }
